import { withDb } from "./db.mjs";
import { RULES, qualifies, signalsOf, ownersOf } from "./derive.mjs";

function buildFacts(account) {
  return {
    account: {
      accountId: account._id,
      name: account.name,
      tier: account.tier,
      region: account.region
    },
    contract: account.contract,
    contacts: account.contacts,
    invoices: account.invoices || [],
    shipments: account.shipments || [],
    regulatoryFlags: account.regulatoryFlags || [],
    supportCases: account.supportCases || [],
    usage: account.usage || {}
  };
}

function dueAt1600Utc(now) {
  const dueAt = new Date(now);
  dueAt.setUTCHours(16, 0, 0, 0);
  if (dueAt <= new Date(now)) dueAt.setUTCDate(dueAt.getUTCDate() + 1);
  return dueAt;
}

function customerMessage(isQualified) {
  return isQualified
    ? "We found several active issues affecting your account and have started a recovery review. Our team is coordinating the response and will share the next update shortly."
    : "We reviewed your account and are continuing standard monitoring. No escalation is needed right now, and we will reach out if that changes.";
}

function auditEvent(isQualified, riskSummary, owners) {
  return {
    summary: isQualified
      ? `Recovery workflow opened. ${riskSummary}. Assigned to: ${owners.join(", ")}.`
      : "Account reviewed. No escalation required.",
    customer_visible: true
  };
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  return withDb(async (db) => {
    const account = await db.collection("accounts").findOne({});
    if (!account) throw new Error("No account found in live database.");

    const facts = buildFacts(account);
    const isQualified = qualifies(facts, now);
    const signals = signalsOf(facts, now);
    const owners = isQualified ? ownersOf(facts, now) : [];
    const status = isQualified ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
    const nextStep = isQualified ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const dueAt = dueAt1600Utc(now);

    await Promise.all([
      db.collection("workflow_state").deleteMany({}),
      db.collection("owner_tasks").deleteMany({}),
      db.collection("customer_messages").deleteMany({}),
      db.collection("audit_events").deleteMany({})
    ]);

    await db.collection("workflow_state").insertOne({
      status,
      next_step: nextStep,
      risk_summary: riskSummary
    });

    if (owners.length > 0) {
      await db.collection("owner_tasks").insertMany(
        owners.map((owner_group) => ({
          owner_group,
          title: `${owner_group} recovery review`,
          due_at: dueAt,
          status: "open"
        }))
      );
    }

    await db.collection("customer_messages").insertOne({
      body: customerMessage(isQualified)
    });

    await db.collection("audit_events").insertOne({
      ...auditEvent(isQualified, riskSummary, owners)
    });
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}

